from tensorflow.keras.models import load_modelimport numpy as npfrom PIL import Imagemodel = load_model("model.h5")def predict_image(image_path):    img = Image.open(image_path).resize((128,128))    img = np.array(img) / 255.0    img = img.reshape(1,128,128,3)    prediction = model.predict(img)[0][0]    if prediction > 0.5:        return "Fake", round(float(prediction), 2)    else:        return "Real", round(float(1 - prediction), 2)